import{_ as a,c as o,o as e,a1 as s}from"./chunks/framework.DDNAyvCW.js";const r="/assets/keys.nJA9szU2.png",u=JSON.parse('{"title":"密钥管理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/keys/index.md","filePath":"docs/manage/keys/index.md"}'),l={name:"docs/manage/keys/index.md"};function n(i,t,d,h,c,p){return e(),o("div",null,t[0]||(t[0]=[s('<h1 id="密钥管理" tabindex="-1">密钥管理 <a class="header-anchor" href="#密钥管理" aria-label="Permalink to &quot;密钥管理&quot;">​</a></h1><p>在一个地方管理你的 SSH 密钥，实现安全的免密码身份验证。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>在添加密钥之前，请确保你已具备：</p><ul><li><strong>Chaterm 已安装</strong>并在你的机器上运行。</li><li><strong>一对 SSH 密钥</strong>（公钥和私钥）。如果你还没有，可以使用 <code>ssh-keygen</code> 或类似工具生成密钥对。</li></ul><h2 id="何时需要密钥" tabindex="-1">何时需要密钥？ <a class="header-anchor" href="#何时需要密钥" aria-label="Permalink to &quot;何时需要密钥？&quot;">​</a></h2><p>当你<a href="/docs/hosts/add-personal">添加主机</a>时，Chaterm 提供两种认证方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>密码</strong></td><td>你知道服务器密码，且尚未在服务器上部署 SSH 密钥。</td></tr><tr><td><strong>密钥</strong></td><td>你已在服务器上部署了公钥，希望无需每次输入密码即可认证。</td></tr></tbody></table><p>如果你选择密钥认证，必须先在此处添加你的私钥，以便 Chaterm 在连接时使用。</p><h2 id="添加密钥" tabindex="-1">添加密钥 <a class="header-anchor" href="#添加密钥" aria-label="Permalink to &quot;添加密钥&quot;">​</a></h2><p><img src="'+r+`" alt=""></p><ol><li>点击左侧菜单栏中的<strong>密钥管理</strong>。</li><li>点击<strong>添加密钥</strong>按钮，打开添加密钥对话框。</li><li>填写以下字段。</li><li>点击<strong>创建</strong>保存密钥。</li></ol><h3 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>必填</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>密钥的名称（例如 <code>生产服务器密钥</code>）。</td><td>是</td></tr><tr><td><strong>私钥</strong></td><td>私钥内容。可以手动粘贴，或将私钥文件拖放到导入区域。</td><td>是</td></tr><tr><td><strong>公钥</strong></td><td>对应的公钥内容。可选，但建议填写以便参考。</td><td>否</td></tr><tr><td><strong>私钥密码</strong></td><td>保护私钥的密码短语（如果在生成密钥时设置了密码）。</td><td>否</td></tr></tbody></table><h3 id="导入方式" tabindex="-1">导入方式 <a class="header-anchor" href="#导入方式" aria-label="Permalink to &quot;导入方式&quot;">​</a></h3><p><strong>文件导入</strong></p><ul><li>将私钥文件拖放到标有&quot;拖拽私钥文件到此处导入&quot;的区域。</li><li>Chaterm 会自动检测密钥格式。支持的格式包括 <code>.pem</code>、<code>.key</code>、<code>.rsa</code> 和 <code>id_rsa</code>。</li></ul><p><strong>手动输入</strong></p><ul><li>将完整的私钥内容粘贴到<strong>私钥</strong>输入框中。内容格式类似：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-----BEGIN RSA PRIVATE KEY-----</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>-----END RSA PRIVATE KEY-----</span></span></code></pre></div></li></ul><h2 id="在主机中使用密钥" tabindex="-1">在主机中使用密钥 <a class="header-anchor" href="#在主机中使用密钥" aria-label="Permalink to &quot;在主机中使用密钥&quot;">​</a></h2><p>添加密钥后，你可以在创建或编辑主机时选择它：</p><ol><li>进入<strong>主机管理</strong>，点击<strong>添加主机</strong>（或编辑已有主机）。</li><li>将<strong>认证方式</strong>设置为<strong>密钥</strong>。</li><li>从下拉列表中选择你添加的密钥。</li><li>保存主机。</li></ol><p>连接该主机时，Chaterm 会自动使用选定的密钥进行身份验证 —— 无需输入密码。</p><p>有关添加主机的完整说明，请参阅<a href="/docs/hosts/add-personal">添加个人主机</a>。</p><h2 id="编辑密钥" tabindex="-1">编辑密钥 <a class="header-anchor" href="#编辑密钥" aria-label="Permalink to &quot;编辑密钥&quot;">​</a></h2><ol><li>在密钥列表中找到要修改的密钥。</li><li>点击<strong>编辑</strong>按钮。</li><li>根据需要更新密钥名称、私钥内容、公钥或密码短语。</li><li>点击<strong>保存</strong>。更改立即生效。</li></ol><h2 id="删除密钥" tabindex="-1">删除密钥 <a class="header-anchor" href="#删除密钥" aria-label="Permalink to &quot;删除密钥&quot;">​</a></h2><ol><li>在密钥列表中找到要删除的密钥。</li><li>点击<strong>删除</strong>按钮。</li><li>在弹出的对话框中确认删除。</li></ol><div class="warning custom-block"><p class="custom-block-title">删除前请注意</p><p>删除密钥是<strong>不可逆</strong>的。在操作之前：</p><ul><li>确认<strong>没有主机正在使用此密钥</strong>进行身份验证。依赖已删除密钥的主机将无法连接。</li><li>如果将来可能还需要该密钥，请在外部备份私钥内容。</li></ul></div>`,29)]))}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
